import json
import os

dirs = [
    '/root/SimpleFlight/scripts/outputs/track_residual/04-11_17-38',
    '/root/SimpleFlight/scripts/outputs/track_residual/04-12_22-15',
    '/root/SimpleFlight/scripts/outputs/track_residual/04-13_22-27',
]

