            if os.path.exists(summary_path):
                with open(summary_path) as f:
                    summary = json.load(f)
                    for key in ['episode_reward', 'episode_len', 'loss', 'entropy', 'policy/mean']:
                        if key in summary:
                            print(f'{key}: {summary[key]}')
    except Exception as e:
        print(f'Error: {e}')
"

