    "baseline": "/root/SimpleFlight/scripts/outputs/track_datt/04-11_02-14",
}

for name, path in dirs.items():
    print(f"\n===== {name} =====")
    try:
        summary_path = os.path.join(path, "wandb")
        run_files = [f for f in os.listdir(summary_path) if f.startswith("run-")]
        if run_files:
            summary_file = os.path.join(summary_path, run_files[0], "files", "wandb-summary.json")
            if os.path.exists(summary_file):
                with open(summary_file) as f:
                    data = json.load(f)
                    # Extract key metrics
                    for key in ['_step', 'episode_error', 'episode_len', 'episode_reward', 
                               'loss_critic', 'loss_actor', 'entropy_loss', 'entropy']:
                        if key in data:
                            val = data[key]
                            if isinstance(val, (int, float)):
                                print(f"  {key}: {val:.6f}" if isinstance(val, float) else f"  {key}: {val}")
    except Exception as e:
        print(f"  Error: {e}")
EOF

